"use client";

import { AppUser, Requisition } from "@/types";
import { formatCurrency } from "@/lib/currencies";
import Link from "next/link";
import { useRouter } from "next/navigation";

interface EmployeeDashboardProps {
    user: AppUser;
    requisitions: Requisition[];
}

export default function EmployeeDashboard({ user, requisitions }: EmployeeDashboardProps) {
    const router = useRouter();

    // Get recent active requests
    const activeRequests = requisitions
        .filter(r => r.status !== 'REJECTED' && r.status !== 'ORDERED')
        .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime())
        .slice(0, 3);

    // Calculate "Buy Again" suggestions (Mock logic: take last 3 approved items)
    // In a real app with more data, we would aggregate by item description
    const buyAgainItems = requisitions
        .filter(r => r.status === 'APPROVED' || r.status === 'ORDERED')
        .flatMap(r => r.items)
        .slice(0, 4);

    return (
        <div style={{ maxWidth: '1200px', margin: '0 auto', color: '#334155' }}>

            {/* Header */}
            <div style={{ marginBottom: '3rem', textAlign: 'center' }}>
                <h1 style={{ fontSize: '2.5rem', fontWeight: 800, color: '#0f172a', marginBottom: '0.5rem' }}>
                    What do you need today?
                </h1>
                <p style={{ fontSize: '1.1rem', color: '#64748b' }}>
                    Select a category to start a new request or track your existing orders.
                </p>
            </div>

            {/* Quick Actions (Apple-style Cards) */}
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '1.5rem', marginBottom: '4rem' }}>
                <Link href="/dashboard/requisitions/new?type=general" style={{ textDecoration: 'none' }}>
                    <div className="card hover-lift" style={{
                        height: '200px',
                        display: 'flex',
                        flexDirection: 'column',
                        alignItems: 'center',
                        justifyContent: 'center',
                        textAlign: 'center',
                        cursor: 'pointer',
                        transition: 'transform 0.2s, box-shadow 0.2s',
                        border: 'none',
                        boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1), 0 2px 4px -1px rgba(0, 0, 0, 0.06)'
                    }}>
                        <div style={{ fontSize: '3.5rem', marginBottom: '1rem' }}>📦</div>
                        <div style={{ fontWeight: 700, fontSize: '1.1rem', color: '#0f172a' }}>General Items</div>
                        <div style={{ fontSize: '0.875rem', color: '#64748b' }}>Office supplies, equipment</div>
                    </div>
                </Link>

                <Link href="/dashboard/requisitions/new?type=service" style={{ textDecoration: 'none' }}>
                    <div className="card hover-lift" style={{
                        height: '200px',
                        display: 'flex',
                        flexDirection: 'column',
                        alignItems: 'center',
                        justifyContent: 'center',
                        textAlign: 'center',
                        cursor: 'pointer',
                        transition: 'transform 0.2s, box-shadow 0.2s',
                        border: 'none',
                        boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1), 0 2px 4px -1px rgba(0, 0, 0, 0.06)'
                    }}>
                        <div style={{ fontSize: '3.5rem', marginBottom: '1rem' }}>🛠️</div>
                        <div style={{ fontWeight: 700, fontSize: '1.1rem', color: '#0f172a' }}>Services</div>
                        <div style={{ fontSize: '0.875rem', color: '#64748b' }}>Contractors, maintenance</div>
                    </div>
                </Link>

                <Link href="/dashboard/requisitions/new?type=travel" style={{ textDecoration: 'none' }}>
                    <div className="card hover-lift" style={{
                        height: '200px',
                        display: 'flex',
                        flexDirection: 'column',
                        alignItems: 'center',
                        justifyContent: 'center',
                        textAlign: 'center',
                        cursor: 'pointer',
                        transition: 'transform 0.2s, box-shadow 0.2s',
                        border: 'none',
                        boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1), 0 2px 4px -1px rgba(0, 0, 0, 0.06)'
                    }}>
                        <div style={{ fontSize: '3.5rem', marginBottom: '1rem' }}>✈️</div>
                        <div style={{ fontWeight: 700, fontSize: '1.1rem', color: '#0f172a' }}>Travel</div>
                        <div style={{ fontSize: '0.875rem', color: '#64748b' }}>Flights, hotels, expensing</div>
                    </div>
                </Link>

                <Link href="/dashboard/requisitions/new?type=software" style={{ textDecoration: 'none' }}>
                    <div className="card hover-lift" style={{
                        height: '200px',
                        display: 'flex',
                        flexDirection: 'column',
                        alignItems: 'center',
                        justifyContent: 'center',
                        textAlign: 'center',
                        cursor: 'pointer',
                        transition: 'transform 0.2s, box-shadow 0.2s',
                        border: 'none',
                        boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1), 0 2px 4px -1px rgba(0, 0, 0, 0.06)'
                    }}>
                        <div style={{ fontSize: '3.5rem', marginBottom: '1rem' }}>💻</div>
                        <div style={{ fontWeight: 700, fontSize: '1.1rem', color: '#0f172a' }}>Software</div>
                        <div style={{ fontSize: '0.875rem', color: '#64748b' }}>Licenses, subscriptions</div>
                    </div>
                </Link>
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: '3rem' }}>

                {/* Active Requests Timeline */}
                <div>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
                        <h2 style={{ fontSize: '1.25rem', fontWeight: 700, color: '#0f172a' }}>Active Requests</h2>
                        <Link href="/dashboard/requisitions" style={{ color: 'var(--primary)', fontWeight: 600, fontSize: '0.9rem', textDecoration: 'none' }}>View All →</Link>
                    </div>

                    {activeRequests.length === 0 ? (
                        <div className="card" style={{ padding: '3rem', textAlign: 'center', backgroundColor: '#f8fafc', border: '1px dashed #e2e8f0' }}>
                            <p style={{ color: '#94a3b8' }}>No active requests. Start a new one above!</p>
                        </div>
                    ) : (
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                            {activeRequests.map(req => (
                                <div key={req.id} className="card hover-scale" style={{
                                    padding: '1.5rem',
                                    display: 'flex',
                                    alignItems: 'center',
                                    gap: '1.5rem',
                                    border: '1px solid #e2e8f0',
                                    transition: 'transform 0.1s'
                                }}>
                                    <div style={{
                                        width: '50px', height: '50px',
                                        borderRadius: '12px',
                                        backgroundColor: req.status === 'APPROVED' ? '#dcfce7' : '#e0f2fe',
                                        color: req.status === 'APPROVED' ? '#166534' : '#0369a1',
                                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                                        fontSize: '1.5rem'
                                    }}>
                                        {req.status === 'APPROVED' ? '✅' : '⏳'}
                                    </div>
                                    <div style={{ flex: 1 }}>
                                        <div style={{ fontWeight: 700, color: '#0f172a', marginBottom: '0.25rem' }}>
                                            {req.items[0]?.description || 'Untitled Request'}
                                            {req.items.length > 1 && <span style={{ fontWeight: 400, color: '#64748b' }}> + {req.items.length - 1} more</span>}
                                        </div>
                                        <div style={{ fontSize: '0.875rem', color: '#64748b' }}>
                                            Submitted {new Date(req.createdAt).toLocaleDateString()} • {formatCurrency(req.totalAmount, req.currency)}
                                        </div>
                                    </div>

                                    {/* Timeline Visual */}
                                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', fontSize: '0.75rem', color: '#64748b' }}>
                                        <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
                                            <div style={{ width: '10px', height: '10px', borderRadius: '50%', backgroundColor: '#22c55e', marginBottom: '4px' }}></div>
                                            <span>Sent</span>
                                        </div>
                                        <div style={{ width: '30px', height: '2px', backgroundColor: req.status !== 'PENDING' ? '#22c55e' : '#e2e8f0' }}></div>
                                        <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
                                            <div style={{ width: '10px', height: '10px', borderRadius: '50%', backgroundColor: req.status !== 'PENDING' ? '#22c55e' : '#e2e8f0', marginBottom: '4px' }}></div>
                                            <span>Manager</span>
                                        </div>
                                        <div style={{ width: '30px', height: '2px', backgroundColor: req.status === 'ORDERED' ? '#22c55e' : '#e2e8f0' }}></div>
                                        <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
                                            <div style={{ width: '10px', height: '10px', borderRadius: '50%', backgroundColor: req.status === 'ORDERED' ? '#22c55e' : '#e2e8f0', marginBottom: '4px' }}></div>
                                            <span>Ordered</span>
                                        </div>
                                    </div>

                                    <div style={{
                                        padding: '0.5rem 1rem',
                                        backgroundColor: '#f1f5f9',
                                        borderRadius: '20px',
                                        fontSize: '0.8rem',
                                        fontWeight: 600,
                                        color: '#475569'
                                    }}>
                                        {req.status}
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>

                {/* Buy Again / Quick Reorder */}
                <div>
                    <h2 style={{ fontSize: '1.25rem', fontWeight: 700, color: '#0f172a', marginBottom: '1.5rem' }}>Buy Again?</h2>
                    {buyAgainItems.length === 0 ? (
                        <div style={{ color: '#94a3b8', fontStyle: 'italic' }}>
                            No recent purchases to recommend.
                        </div>
                    ) : (
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                            {buyAgainItems.map((item, idx) => (
                                <div key={idx} className="card" style={{
                                    padding: '1rem',
                                    display: 'flex',
                                    justifyContent: 'space-between',
                                    alignItems: 'center',
                                    border: '1px solid #e2e8f0'
                                }}>
                                    <div>
                                        <div style={{ fontWeight: 600, fontSize: '0.9rem', color: '#334155' }}>{item.description}</div>
                                        <div style={{ fontSize: '0.8rem', color: '#94a3b8' }}>Last price: {formatCurrency(item.unitPrice, 'USD')}</div>
                                    </div>
                                    <button
                                        className="btn-text"
                                        style={{
                                            color: 'var(--primary)', fontWeight: 600, fontSize: '0.8rem',
                                            padding: '0.25rem 0.5rem',
                                            backgroundColor: '#e0f2fe',
                                            borderRadius: '6px'
                                        }}
                                        onClick={() => router.push(`/dashboard/requisitions/new?reorder=${encodeURIComponent(item.description)}`)}
                                    >
                                        + Add
                                    </button>
                                </div>
                            ))}
                        </div>
                    )}
                </div>

            </div>

            <style jsx>{`
                .hover-lift:hover {
                    transform: translateY(-5px);
                    box-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.1), 0 4px 6px -2px rgba(0, 0, 0, 0.05) !important;
                }
                .hover-scale:hover {
                    transform: scale(1.01);
                }
            `}</style>
        </div>
    );
}
