"use client";

import { AppUser, DashboardEvent } from "@/types";
import { formatCurrency } from "@/lib/currencies";
import { useState, useEffect } from "react";
import Link from "next/link";
import { SpendBarChart, BudgetDonutChart } from "@/components/charts/SimpleCharts";
import { VendorPerformance } from "@/lib/vendorAnalytics";

interface ExecutiveDashboardProps {
    user: AppUser;
    stats: {
        pendingCount: number;
        activeCount: number;
        totalSpend: number;
        savings: number;
        budgetUsage: { total: number; used: number; percent: number };
        monthlyData: any[];
        spendByCategory?: Record<string, number>;
    };
    vendorPerf: VendorPerformance[];
}

export default function ExecutiveDashboard({ user, stats, vendorPerf }: ExecutiveDashboardProps) {
    const [greeting, setGreeting] = useState("Good Morning");
    const [currentTime, setCurrentTime] = useState<Date | null>(null);

    // Dynamic Time-Based Greeting
    useEffect(() => {
        const updateTime = () => {
            const now = new Date();
            setCurrentTime(now);
            const hour = now.getHours();

            if (hour < 12) setGreeting("Good Morning");
            else if (hour < 17) setGreeting("Good Afternoon");
            else setGreeting("Good Evening");
        };

        updateTime();
        const interval = setInterval(updateTime, 60000); // Update every minute
        return () => clearInterval(interval);
    }, []);

    // Calculate Available to Spend
    const availableBudget = (stats.budgetUsage.total || 0) - (stats.budgetUsage.used || 0);

    return (
        <div style={{ color: '#1e293b' }}>
            {/* HEROTR: Command Center Header */}
            <div className="card" style={{
                background: 'linear-gradient(135deg, #0f172a 0%, #1e293b 100%)',
                color: 'white',
                padding: '2.5rem',
                borderRadius: '16px',
                marginBottom: '2rem',
                position: 'relative',
                overflow: 'hidden',
                boxShadow: '0 10px 25px -5px rgba(15, 23, 42, 0.3)'
            }}>
                {/* Decorative Elements */}
                <div style={{ position: 'absolute', top: 0, right: 0, width: '300px', height: '300px', background: 'radial-gradient(circle, rgba(255,255,255,0.05) 0%, rgba(255,255,255,0) 70%)', transform: 'translate(30%, -30%)' }}></div>

                <div style={{ position: 'relative', zIndex: 1 }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                        <div>
                            <div style={{
                                textTransform: 'uppercase',
                                letterSpacing: '0.1em',
                                fontSize: '0.75rem',
                                color: '#94a3b8',
                                marginBottom: '0.5rem',
                                display: 'flex',
                                alignItems: 'center',
                                gap: '0.5rem'
                            }}>
                                <span style={{ width: '8px', height: '8px', backgroundColor: '#22c55e', borderRadius: '50%', display: 'inline-block' }}></span>
                                Executive Command Center
                            </div>
                            <h1 style={{ fontSize: '2.5rem', fontWeight: 800, marginBottom: '0.5rem', letterSpacing: '-0.02em' }}>
                                {greeting}, {user.displayName?.split(' ')[0]}.
                            </h1>
                            <p style={{ color: '#cbd5e1', fontSize: '1.1rem', maxWidth: '600px', lineHeight: 1.5 }}>
                                You have <strong style={{ color: 'white' }}>{stats.pendingCount} items</strong> requiring your attention today.
                                Your department has utilized <strong style={{ color: stats.budgetUsage.percent > 90 ? '#f87171' : 'white' }}>{Math.round(stats.budgetUsage.percent)}%</strong> of the annual budget.
                            </p>
                        </div>
                        <div style={{ textAlign: 'right' }}>
                            <div style={{ fontSize: '3rem', fontWeight: 200, fontFamily: 'monospace', opacity: 0.8 }}>
                                {currentTime?.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                            </div>
                            <div style={{ color: '#94a3b8' }}>
                                {currentTime?.toLocaleDateString([], { weekday: 'long', month: 'long', day: 'numeric' })}
                            </div>
                        </div>
                    </div>

                    {/* Quick Stats Strip */}
                    <div style={{
                        display: 'flex',
                        gap: '3rem',
                        marginTop: '2.5rem',
                        borderTop: '1px solid rgba(255,255,255,0.1)',
                        paddingTop: '1.5rem'
                    }}>
                        <div style={{ flex: 1 }}>
                            <div style={{ fontSize: '0.8rem', color: '#94a3b8', marginBottom: '0.25rem' }}>Pending Approvals</div>
                            <div style={{ fontSize: '1.5rem', fontWeight: 700 }}>
                                {stats.pendingCount}
                            </div>
                            {stats.pendingCount > 0 && <Link href="/dashboard/approvals" style={{ fontSize: '0.8rem', color: '#fbbf24', textDecoration: 'none' }}>Review Now →</Link>}
                        </div>
                        <div style={{ flex: 1 }}>
                            <div style={{ fontSize: '0.8rem', color: '#94a3b8', marginBottom: '0.25rem' }}>Budget Remaining</div>
                            <div style={{ fontSize: '1.5rem', fontWeight: 700 }}>
                                {formatCurrency(availableBudget || 0, 'USD')}
                            </div>
                            <div style={{ fontSize: '0.8rem', color: '#94a3b8' }}>Total: {formatCurrency(stats.budgetUsage.total || 0, 'USD')}</div>
                        </div>
                        <div style={{ flex: 1 }}>
                            <div style={{ fontSize: '0.8rem', color: '#94a3b8', marginBottom: '0.25rem' }}>Annual Savings</div>
                            <div style={{ fontSize: '1.5rem', fontWeight: 700, color: '#22c55e' }}>
                                {formatCurrency(stats.savings, 'USD')}
                            </div>
                            <div style={{ fontSize: '0.8rem', color: '#94a3b8' }}>Negotiated YTD</div>
                        </div>
                    </div>
                </div>
            </div>

            {/* Main Content Grid */}
            <div style={{ display: 'grid', gridTemplateColumns: 'minmax(0, 2fr) minmax(0, 1fr)', gap: '2rem' }}>

                {/* Left Column: Approvals & Analytics */}
                <div style={{ display: 'flex', flexDirection: 'column', gap: '2rem' }}>

                    {/* Action Deck */}
                    {stats.pendingCount > 0 ? (
                        <div className="card" style={{ borderLeft: '4px solid #f59e0b' }}>
                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
                                <h2 style={{ fontSize: '1.25rem', fontWeight: 700 }}>📢 Priority Approvals</h2>
                                <Link href="/dashboard/approvals" className="btn btn-primary" style={{ fontSize: '0.9rem' }}>
                                    Process Queue ({stats.pendingCount})
                                </Link>
                            </div>
                            <p style={{ color: 'var(--text-secondary)', marginBottom: '1rem' }}>
                                Strategies for effective spend management suggest reviewing these items early in the day.
                            </p>
                            {/* We could embed a mini-list here later */}
                        </div>
                    ) : (
                        <div className="card" style={{ borderLeft: '4px solid #22c55e', backgroundColor: '#f0fdf4' }}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                                <div style={{ fontSize: '2rem' }}>✅</div>
                                <div>
                                    <h2 style={{ fontSize: '1.1rem', fontWeight: 700, color: '#166534' }}>All Caught Up</h2>
                                    <p style={{ color: '#15803d', margin: 0 }}>You have zero pending approvals. Great job keeping the pipeline clear!</p>
                                </div>
                            </div>
                        </div>
                    )}

                    {/* Spend Trend Analysis */}
                    <div className="card">
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
                            <h2 style={{ fontSize: '1.1rem', fontWeight: 700 }}>Expenditure Analytics</h2>
                            <select style={{ padding: '0.5rem', border: '1px solid #e2e8f0', borderRadius: '6px', fontSize: '0.875rem' }}>
                                <option>This Fiscal Year</option>
                                <option>Last Quarter</option>
                            </select>
                        </div>
                        <SpendBarChart data={stats.monthlyData} />
                    </div>
                </div>

                {/* Right Column: Financial Pulse */}
                <div style={{ display: 'flex', flexDirection: 'column', gap: '2rem' }}>

                    {/* Budget Health (Financial Pulse) */}
                    <div className="card">
                        <h2 style={{ fontSize: '1.1rem', fontWeight: 700, marginBottom: '1.5rem' }}>💰 Financial Pulse</h2>
                        <div style={{ display: 'flex', justifyContent: 'center', padding: '1rem 0' }}>
                            <BudgetDonutChart total={stats.budgetUsage.total || 1000} used={stats.budgetUsage.used || 0} />
                        </div>
                        <div style={{ textAlign: 'center', marginTop: '1rem' }}>
                            <div style={{ fontSize: '2rem', fontWeight: 700, color: '#1e293b' }}>
                                {Math.round(stats.budgetUsage.percent)}%
                            </div>
                            <div style={{ color: '#64748b', fontSize: '0.875rem' }}>Budget Utilized</div>
                        </div>

                        <div style={{ marginTop: '2rem', display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                            <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '0.9rem', paddingBottom: '0.5rem', borderBottom: '1px solid #f1f5f9' }}>
                                <span style={{ color: '#64748b' }}>Allocated</span>
                                <span style={{ fontWeight: 600 }}>{formatCurrency(stats.budgetUsage.total || 0, 'USD')}</span>
                            </div>
                            <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '0.9rem', paddingBottom: '0.5rem', borderBottom: '1px solid #f1f5f9' }}>
                                <span style={{ color: '#64748b' }}>Spent (YTD)</span>
                                <span style={{ fontWeight: 600 }}>{formatCurrency(stats.budgetUsage.used || 0, 'USD')}</span>
                            </div>
                            <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '0.9rem', paddingBottom: '0.5rem', borderBottom: '1px solid #f1f5f9' }}>
                                <span style={{ color: '#64748b' }}>Available</span>
                                <span style={{ fontWeight: 700, color: '#22c55e' }}>{formatCurrency(availableBudget || 0, 'USD')}</span>
                            </div>
                        </div>
                    </div>

                    {/* Department Spending Breakdown */}
                    <div className="card">
                        <h2 style={{ fontSize: '1.1rem', fontWeight: 700, marginBottom: '1rem' }}>Top Dimensions</h2>
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                            {stats.spendByCategory && Object.entries(stats.spendByCategory).sort(([, a], [, b]) => b - a).slice(0, 4).map(([category, amount], i) => (
                                <div key={category}>
                                    <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '0.875rem', marginBottom: '0.25rem' }}>
                                        <span>{category}</span>
                                        <span style={{ fontWeight: 600 }}>{formatCurrency(amount, 'USD')}</span>
                                    </div>
                                    <div style={{ height: '4px', width: '100%', backgroundColor: '#f1f5f9', borderRadius: '2px' }}>
                                        <div style={{
                                            height: '100%',
                                            width: `${Math.min((amount / stats.totalSpend) * 100, 100)}%`,
                                            backgroundColor: i === 0 ? '#3b82f6' : i === 1 ? '#8b5cf6' : '#cbd5e1',
                                            borderRadius: '2px'
                                        }}></div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* Partner Performance Widget (Phase 18) */}
                    <div className="card">
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
                            <h2 style={{ fontSize: '1.1rem', fontWeight: 700 }}>🏆 Partner Intelligence</h2>
                        </div>
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
                            {vendorPerf.slice(0, 3).map((v) => (
                                <div key={v.vendorId} style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                                    <div style={{
                                        width: '40px', height: '40px', borderRadius: '50%',
                                        backgroundColor: v.rank === 1 ? '#fef9c3' : v.rank === 2 ? '#f1f5f9' : '#fff7ed',
                                        color: v.rank === 1 ? '#ca8a04' : v.rank === 2 ? '#64748b' : '#c2410c',
                                        display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 800
                                    }}>
                                        #{v.rank}
                                    </div>
                                    <div style={{ flex: 1 }}>
                                        <div style={{ fontWeight: 600, fontSize: '0.9rem' }}>{v.vendorName}</div>
                                        <div style={{ fontSize: '0.75rem', color: '#64748b' }}>
                                            {formatCurrency(v.totalSpend, 'USD')} • {v.totalOrders} Orders
                                        </div>
                                    </div>
                                    <div style={{ textAlign: 'right' }}>
                                        <div style={{
                                            fontWeight: 700, fontSize: '0.9rem',
                                            color: v.reliabilityScore >= 95 ? '#22c55e' : v.reliabilityScore >= 80 ? '#eab308' : '#ef4444'
                                        }}>
                                            {v.reliabilityScore}%
                                        </div>
                                        <div style={{ fontSize: '0.7rem', color: '#94a3b8' }}>Reliability</div>
                                    </div>
                                </div>
                            ))}
                            {vendorPerf.length === 0 && (
                                <div style={{ textAlign: 'center', color: '#94a3b8', fontStyle: 'italic', fontSize: '0.875rem' }}>
                                    Not enough data to rank partners yet.
                                </div>
                            )}
                        </div>
                    </div>

                </div>
            </div>
        </div>
    );
}
